export function getInstalledSdks(rootDir) {
    const workspaces = detectWorkspaces(rootDir);
    const dirs = [
        { dir: rootDir, workspacePath: "." },
        ...workspaces.map((d) => ({
            dir: d,
            workspacePath: path.relative(rootDir, d) || ".",
        })),
    ];
    const seen = new Set();
    const results = [];
    for (const { dir, workspacePath } of dirs) {
        for (const sdk of detectAtDir(dir, rootDir, workspacePath)) {
            const key = `${workspacePath}\0${sdk.language}`;
            if (seen.has(key)) {
                continue;
            }
            seen.add(key);
            results.push(sdk);
        }
    }
    return results;
}
export function getCurrentVersion(sdk) {
    return sdk.resolvedVersion ?? sdk.declaredVersion;
}
